import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { FaMapMarkedAlt, FaGlobeAsia, FaBook, FaChartLine, FaArrowRight, FaPlane, FaCompass, FaRoute } from 'react-icons/fa';
import './LandingPage.css';

const features = [
  {
    icon: <FaMapMarkedAlt />,
    title: 'India Map Dashboard',
    desc: 'Interactive map to track every state and union territory you\'ve visited across India.'
  },
  {
    icon: <FaGlobeAsia />,
    title: 'World Map Explorer',
    desc: 'Pin countries on the world map and build your global travel portfolio.'
  },
  {
    icon: <FaBook />,
    title: 'Travel Journal',
    desc: 'Log destinations, mark favorites, and track your exploration progress by region.'
  },
  {
    icon: <FaChartLine />,
    title: 'Travel Statistics',
    desc: 'Beautiful analytics showing your travel patterns, milestones, and achievements.'
  },
];

const stats = [
  { value: '36', label: 'States & UTs' },
  { value: '195+', label: 'Countries' },
  { value: '1000+', label: 'Destinations' },
];

export default function LandingPage() {
  const navigate = useNavigate();
  const [scrollY, setScrollY] = useState(0);
  const mapRef = useRef(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) navigate('/dashboard');
  }, [navigate]);

  // Load the real world map SVG
  useEffect(() => {
    if (!mapRef.current) return;
    fetch('/WorldMap_SVG_Source.normalized.svg')
      .then(res => res.text())
      .then(svgContent => {
        if (mapRef.current) {
          mapRef.current.innerHTML = svgContent;
          const svg = mapRef.current.querySelector('svg');
          if (svg) {
            svg.setAttribute('width', '100%');
            svg.setAttribute('height', '100%');
            svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
            svg.style.display = 'block';
            // Style all country paths
            svg.querySelectorAll('path').forEach(path => {
              path.style.fill = '#c7d2e8';
              path.style.stroke = '#e2e8f0';
              path.style.strokeWidth = '0.5';
              path.style.transition = 'fill 0.3s ease';
            });
            // Highlight some countries to show "visited" effect
            const highlights = ['India', 'Japan', 'France', 'Brazil', 'Australia', 'United States', 'Thailand', 'Italy', 'Germany', 'Canada'];
            svg.querySelectorAll('g').forEach(g => {
              const title = g.querySelector('title');
              if (title && highlights.includes(title.textContent)) {
                g.querySelectorAll('path').forEach(p => {
                  p.style.fill = '#6ee7b7';
                  p.style.stroke = '#34d399';
                });
              }
            });
          }
        }
      });
  }, []);

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="landing">
      {/* Navigation */}
      <nav className={`landing-nav ${scrollY > 50 ? 'scrolled' : ''}`}>
        <div className="landing-nav-inner">
          <div className="landing-logo">
            <FaCompass className="landing-logo-icon" />
            <span>TravelTracker</span>
          </div>
          <div className="landing-nav-actions">
            <button className="nav-btn-ghost" onClick={() => navigate('/login')}>Log In</button>
            <button className="nav-btn-primary" onClick={() => navigate('/signup')}>
              Get Started <FaArrowRight />
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="landing-hero">
        <div className="hero-bg-shapes">
          <div className="hero-shape hero-shape-1" />
          <div className="hero-shape hero-shape-2" />
          <div className="hero-shape hero-shape-3" />
        </div>
        <div className="hero-content">
          <div className="hero-badge">
            <FaPlane /> Your Travel Companion
          </div>
          <h1 className="hero-title">
            Track Your Journeys<br />
            <span className="hero-gradient-text">Across India & The World</span>
          </h1>
          <p className="hero-subtitle">
            Visualize your travels on interactive maps, journal your adventures,
            and watch your exploration progress grow with beautiful analytics.
          </p>
          <div className="hero-actions">
            <button className="hero-btn-primary" onClick={() => navigate('/signup')}>
              Start Tracking Free <FaArrowRight />
            </button>
            <button className="hero-btn-secondary" onClick={() => navigate('/login')}>
              I have an account
            </button>
          </div>
          <div className="hero-stats">
            {stats.map((stat, i) => (
              <div key={i} className="hero-stat">
                <div className="hero-stat-value">{stat.value}</div>
                <div className="hero-stat-label">{stat.label}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="hero-visual">
          <div className="hero-map-real">
            <div className="hero-map-container" ref={mapRef} />
            {/* Pulsing dots on the map */}
            <div className="hero-pulse-dot" style={{ top: '35%', left: '72%' }} />
            <div className="hero-pulse-dot delay-1" style={{ top: '30%', left: '50%' }} />
            <div className="hero-pulse-dot delay-2" style={{ top: '55%', left: '28%' }} />
            <div className="hero-pulse-dot delay-3" style={{ top: '25%', left: '20%' }} />
            <div className="hero-pulse-dot delay-4" style={{ top: '45%', left: '48%' }} />
            {/* Floating cards */}
            <div className="hero-floating-card hero-float-1">
              <FaRoute />
              <span>12 States Visited</span>
            </div>
            <div className="hero-floating-card hero-float-2">
              <FaGlobeAsia />
              <span>5 Countries</span>
            </div>
          </div>
        </div>
      </section>

      {/* Features Section */}
      <section className="landing-features">
        <div className="features-header">
          <h2>Everything You Need to<br /><span className="hero-gradient-text">Track Your Adventures</span></h2>
          <p>Powerful features designed for the modern traveler</p>
        </div>
        <div className="features-grid">
          {features.map((f, i) => (
            <div key={i} className="feature-card" style={{ animationDelay: `${i * 0.1}s` }}>
              <div className="feature-icon">{f.icon}</div>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* How It Works */}
      <section className="landing-how">
        <div className="how-header">
          <h2>How It <span className="hero-gradient-text">Works</span></h2>
          <p>Get started in three simple steps</p>
        </div>
        <div className="how-steps">
          <div className="how-step">
            <div className="how-step-num">1</div>
            <h3>Create Account</h3>
            <p>Sign up for free and set up your travel profile in seconds.</p>
          </div>
          <div className="how-connector" />
          <div className="how-step">
            <div className="how-step-num">2</div>
            <h3>Mark Visited Places</h3>
            <p>Click on states and countries on interactive maps to track your travels.</p>
          </div>
          <div className="how-connector" />
          <div className="how-step">
            <div className="how-step-num">3</div>
            <h3>Track Progress</h3>
            <p>Watch your stats grow, unlock milestones, and plan your next adventure.</p>
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="landing-cta">
        <div className="cta-content">
          <h2>Ready to Map Your Adventures?</h2>
          <p>Join thousands of travelers tracking their journeys</p>
          <button className="hero-btn-primary" onClick={() => navigate('/signup')}>
            Create Free Account <FaArrowRight />
          </button>
        </div>
      </section>

      {/* Footer */}
      <footer className="landing-footer">
        <div className="footer-inner">
          <div className="landing-logo">
            <FaCompass className="landing-logo-icon" />
            <span>TravelTracker</span>
          </div>
          <p>Built with love for travelers everywhere</p>
        </div>
      </footer>
    </div>
  );
}
